#!/usr/bin/env node
// Reconstruct the loadable memory image of an ELF64 binary and emit
// { "<address>": <uint32 little-endian value>, ... } for every 4-byte
// word backed by file contents in a PT_LOAD segment.
// Memory base for the lowest segment is 0x400000 (addr = 0x400000 + p_vaddr).

const fs = require('fs');

const path = process.argv[2];
if (!path) {
  process.stderr.write('usage: node extract.js <elf-binary>\n');
  process.exit(1);
}

const buf = fs.readFileSync(path);

// ELF magic check
if (!(buf[0] === 0x7f && buf[1] === 0x45 && buf[2] === 0x4c && buf[3] === 0x46)) {
  process.stderr.write('not an ELF file\n');
  process.exit(1);
}

const ei_class = buf[4]; // 1=32bit, 2=64bit
if (ei_class !== 2) {
  process.stderr.write('only ELF64 is supported\n');
  process.exit(1);
}

const BASE = 0x400000n;
const PT_LOAD = 1;

// ELF64 header offsets
const e_phoff = buf.readBigUInt64LE(0x20);
const e_phentsize = buf.readUInt16LE(0x36);
const e_phnum = buf.readUInt16LE(0x38);

const result = {};

for (let i = 0; i < e_phnum; i++) {
  const ph = Number(e_phoff) + i * e_phentsize;
  const p_type = buf.readUInt32LE(ph + 0x00);
  if (p_type !== PT_LOAD) continue;

  const p_offset = buf.readBigUInt64LE(ph + 0x08);
  const p_vaddr = buf.readBigUInt64LE(ph + 0x10);
  const p_filesz = buf.readBigUInt64LE(ph + 0x20);

  const off = Number(p_offset);
  const filesz = Number(p_filesz);

  for (let o = 0; o + 4 <= filesz; o += 4) {
    const filePos = off + o;
    if (filePos + 4 > buf.length) break;
    const addr = BASE + p_vaddr + BigInt(o);
    const val = buf.readUInt32LE(filePos);
    result[addr.toString()] = val;
  }
}

process.stdout.write(JSON.stringify(result));
process.stdout.write('\n');

